17	// RBTDRF — handbook-render fast-tier fixture for theurge
18	//
19	// Exercises every handbook display tabtarget and reports per-case pass/fail.
20	// Each case invokes a handbook colophon with no arguments and asserts exit 0.
21	
22	use std::path::Path;
23	
24	use crate::case;
25	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
26	use crate::rbtdri_invocation::{rbtdri_find_tabtarget_global, rbtdri_tabtarget_command};
27	use crate::rbtdgc_consts::{
28	    RBTDGC_HANDBOOK_TOP, RBTDGC_HANDBOOK_WINDOWS,
29	    RBTDGC_HW_DOCKER_CONTEXT, RBTDGC_HW_DOCKER_DESKTOP,
30	    RBTDGC_ONBOARD_CRASH_COURSE, RBTDGC_ONBOARD_CRED_DIRECTOR,
31	    RBTDGC_ONBOARD_CRED_RETRIEVER, RBTDGC_ONBOARD_DIR_FIRST_BUILD,
32	    RBTDGC_ONBOARD_FIRST_CRUCIBLE, RBTDGC_ONBOARD_GOVERNOR_HB,
33	    RBTDGC_ONBOARD_PAYOR_HB, RBTDGC_ONBOARD_START_HERE,
34	    RBTDGC_PAYOR_ESTABLISH, RBTDGC_PAYOR_REFRESH,
35	    RBTDGC_QUOTA_BUILD,
36	};
37	use crate::rbtdrm_manifest::RBTDRM_FIXTURE_HANDBOOK_RENDER;
38	
39	// ── Helper ───────────────────────────────────────────────────
40	
41	/// Invoke a handbook tabtarget with no arguments and return Pass iff exit 0.
42	/// Writes stdout/stderr traces to the per-case directory for diagnostic review.
43	fn rbtdrf_hb_render(dir: &Path, colophon: &str, label: &str) -> rbtdre_Verdict {
44	    let root = match std::env::current_dir() {
45	        Ok(r) => r,
46	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
47	    };
48	
49	    let tt = match rbtdri_find_tabtarget_global(&root, colophon) {
50	        Ok(p) => p,
51	        Err(e) => return rbtdre_Verdict::Fail(e),
52	    };
53	
54	    let output = match rbtdri_tabtarget_command(&tt).current_dir(&root).output() {
55	        Ok(o) => o,
56	        Err(e) => {
57	            return rbtdre_Verdict::Fail(format!(
58	                "{}: failed to run {}: {}",
59	                label,
60	                tt.display(),
61	                e
62	            ));
63	        }
64	    };
65	
66	    let code = output.status.code().unwrap_or(-1);
67	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &output.stdout);
68	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &output.stderr);
69	
70	    if code != 0 {
71	        return rbtdre_Verdict::Fail(format!(
72	            "{}: {} exited {} — {}",
73	            label,
74	            colophon,
75	            code,
76	            String::from_utf8_lossy(&output.stderr),
77	        ));
78	    }
79	    rbtdre_Verdict::Pass
80	}
